import os
import logging
from datetime import datetime
from flask import Flask, request, jsonify

app = Flask(__name__)

# Configure logging to a file
log_file = 'application.log'
logging.basicConfig(level=logging.INFO,
                    format='%(asctime)s - %(levelname)s - %(message)s',
                    handlers=[
                        logging.FileHandler(log_file)
                    ])

# In a real application, you'd use a database to store user credentials securely (hashed passwords)
# For this example, we'll use a simple dictionary
USERS = {
    "user1": {"password": "password1", "email": "user1@example.com"},
    "admin": {"password": "adminpass", "email": "admin@example.com"},
}

@app.route('/login', methods=['POST'])
def login():
    username = request.form.get('username')
    password = request.form.get('password')
    email = request.form.get('email', 'not_provided') # Email is not strictly required for login, but might be provided
    ip_address = request.remote_addr
    user_agent = request.headers.get('User-Agent')

    # Log all login attempts with sensitive information
    logging.info(f"LOGIN_ATTEMPT: Username='{username}', Password='{password}', Email='{email}', IP='{ip_address}', UserAgent='{user_agent}'")

    if username in USERS and USERS[username]['password'] == password:
        return jsonify({"message": "Login successful", "username": username}), 200
    else:
        return jsonify({"message": "Invalid credentials"}), 401

@app.route('/health', methods=['GET'])
def health_check():
    return jsonify({"status": "healthy"}), 200

if __name__ == '__main__':
    # Ensure the log file exists for initial setup if needed
    if not os.path.exists(log_file):
        open(log_file, 'a').close()

    # In a production environment, you would not run with debug=True
    # and you would use a production-ready WSGI server like Gunicorn or uWSGI.
    app.run(debug=True, host='0.0.0.0', port=5000)